import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a string to handle both real newlines and escaped "\\n" sequences
        String input = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        // Convert escaped newlines ("\\n") to real newlines
        input = input.replace("\\n", "\n");
        // Use a Scanner with whitespace delimiter to parse integers safely
        Scanner sc = new Scanner(input);
        StringBuilder out = new StringBuilder();
        if (!sc.hasNextInt()) {
            return;
        }
        int T = sc.nextInt();
        for (int t = 0; t < T; t++) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[][] mat = new int[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    mat[i][j] = sc.nextInt();
                }
            }
            // Efficient O(N+M) scan from top-right corner
            int bestRow = 1; // default to first row (1‑based)
            int col = M - 1;
            int rowIdx = 0;
            while (rowIdx < N && col >= 0) {
                if (mat[rowIdx][col] == 1) {
                    bestRow = rowIdx + 1; // found a row with more leftmost 1
                    col--; // try to move left for even more 1s in this row
                } else {
                    rowIdx++; // move down to next row
                }
            }
            out.append(bestRow);
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

